custom_css:
/* Example CSS for your font: lxgwwenkai-medium */

/* Apply to all text */
:root * {
	--font-default: 'lxgwwenkai-medium';
	--default-font: 'lxgwwenkai-medium';
	--font-family-editor: 'lxgwwenkai-medium';
	--font-interface-override: 'lxgwwenkai-medium';
	--font-text-override: 'lxgwwenkai-medium';
}

/* Example: Apply to custom CSS class */
.custom-font * {
	font-family: 'lxgwwenkai-medium' !important;
}

/* Example: Apply to specific elements only */
.custom-font h1, .custom-font h2, .custom-font h3 {
	font-family: 'lxgwwenkai-medium' !important;
}
